  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params  // ✅ CORRECT
}
```

**Type-safe approach using RouteContext helper:**
```typescript
import type { NextRequest } from 'next/server'

export async function GET(_req: NextRequest, ctx: RouteContext<'/api/posts/[id]'>) {
  const { id } = await ctx.params
  return Response.json({ id })
}
```

#### Streaming Responses - Key Pattern
```typescript
export async function POST(req: Request) {
  const { messages } = await req.json()
  const result = await streamText({
    model: openai('gpt-4-turbo'),
    messages,
  })
  return new StreamingTextResponse(result.toAIStream())
}
```

#### Route Handler Caching Changed (v15 broke this from v14)
- `GET` handlers are **NOT cached by default** (changed in v15, still true in v16)
- To cache GET: use `export const dynamic = 'force-static'`
- Other HTTP methods are NEVER cached

```typescript
export const dynamic = 'force-static'

export async function GET() {
  const data = await fetch('https://...')
  return Response.json(data)
}
```

### 2. **Layouts & Pages - BREAKING CHANGES**

#### Async params & searchParams (v15 → v16 BREAKING)
In v16, synchronous access is **completely removed** - no temporary compatibility mode:

```typescript
// OLD (v14)
export default async function Page({ params, searchParams }) {
  const { slug } = params  // ❌ FAILS IN v16
  return <div>{slug}</div>
}

// NEW (v16 - for async components)
export default async function Page(props: PageProps<'/blog/[slug]'>) {
  const { slug } = await props.params
  const query = await props.searchParams
  return <div>{slug} {query}</div>
}

// NEW (v16 - for sync/client components, use React.use())
import { use } from 'react'

export default function Page(props: PageProps<'/blog/[slug]'>) {
  const { slug } = use(props.params)
  const query = use(props.searchParams)
  return <div>{slug}</div>
}
```

**Important for searchParams:**
```typescript
type SearchParams = Promise<{ [key: string]: string | string[] | undefined }>

export default async function Page(props: {
  searchParams: SearchParams
}) {
  const params = await props.searchParams
  const page = params.page  // Now this works
}
```

### 3. **Dynamic Routes - Async Params Pattern**

The pattern for dynamic segments changed significantly:

```typescript
// OLD (v14)
export default function Page({ params }: { params: { slug: string } }) {
  const { slug } = params
}

// NEW (v16) - Server Component
export default async function Page({ params }: PageProps<'/blog/[slug]'>) {
  const { slug } = await params
  const post = await getPost(slug)
  return <article>{post.title}</article>
}

// NEW (v16) - Client Component
'use client'
import { use } from 'react'

export default function Page({ params }: PageProps<'/blog/[slug]'>) {
  const { slug } = use(params)
  return <div>{slug}</div>
}
```

#### generateStaticParams Still Works:
```typescript
export async function generateStaticParams() {
  return [{ slug: 'post-1' }, { slug: 'post-2' }]
}

export default async function Page({ params }: PageProps<'/blog/[slug]'>) {
  const { slug } = await params
  const post = await getPost(slug)
  return <h1>{post.title}</h1>
}
```

### 4. **Request APIs (cookies, headers, draftMode) - BREAKING CHANGE**

All now `async` with **no fallback** in v16:

```typescript
// OLD (v14)
import { cookies, headers } from 'next/headers'

const cookieStore = cookies()
const token = cookieStore.get('token')

// NEW (v16 - REQUIRED)
import { cookies, headers } from 'next/headers'

const cookieStore = await cookies()
const token = cookieStore.get('token')

// In route handlers:
export async function GET(request: NextRequest) {
  const headersList = await headers()
  const userAgent = headersList.get('user-agent')

  const cookieStore = await cookies()
  const sessionId = cookieStore.get('sessionId')?.value
}
```

### 5. **New v16-Specific Features**

#### Caching APIs - New Functions
```typescript
// revalidateTag with cacheLife profile
import { revalidateTag } from 'next/cache'

export async function updateArticle(articleId: string) {
  revalidateTag(`article-${articleId}`, 'max')  // New 2nd param
}

// updateTag for read-your-writes semantics (SERVER ACTIONS ONLY)
import { updateTag } from 'next/cache'

export async function updateUserProfile(userId: string, profile: Profile) {
  await db.users.update(userId, profile)
  updateTag(`user-${userId}`)  // Expires & refreshes immediately
}

// refresh for client router refresh from Server Actions
import { refresh } from 'next/cache'

export async function markNotificationAsRead(id: string) {
  await db.notifications.markAsRead(id)
  refresh()  // Refresh client router
}
```

#### cacheLife and cacheTag are now stable (no unstable_ prefix needed)
```typescript
import { cacheLife, cacheTag } from 'next/cache'

async function getData() {
  'use cache'
  cacheLife('hours')
  cacheTag('data')
  return await fetchData()
}
```

### 6. **fetch() Behavior Changed (v15)**
Still true in v16:

```typescript
// NOT cached by default
const data = await fetch('https://...')

// Explicitly cache with force-cache
const cached = await fetch('https://...', { cache: 'force-cache' })

// Or use segment config
export const fetchCache = 'default-cache'

export default async function Layout() {
  const a = await fetch('...')  // Cached due to segment config
  const b = await fetch('...', { cache: 'no-store' })  // Not cached
}
```

### 7. **Image Component Breaking Changes (v16)**

```typescript
// Query strings now require configuration
export const nextConfig: NextConfig = {
  images: {
    localPatterns: [
      {
        pathname: '/assets/**',
        search: '?v=1',  // Must allow specific query strings
      },
    ],
  },
}

// Default cache behavior changed
// minimumCacheTTL: 60s → 4 hours (14400s)
// imageSizes: removed 16px size
// qualities: now only [75] by default
// maximumRedirects: unlimited → 3
// images.domains: DEPRECATED - use remotePatterns instead
```

### 8. **Key Gotchas**

1. **No synchronous params access in v16** - Always await or use React.use()
2. **Route handlers can't have page.js at same level** - You get a build error
3. **GET handlers aren't cached by default** - Must opt in with `dynamic = 'force-static'`
4. **searchParams opts page into dynamic rendering** - Using it means no static prerendering
5. **Middleware renamed to proxy in v16** - Files should be `proxy.ts` not `middleware.ts`
6. **Turbopack is default now** - Next.js uses Turbopack by default, not Webpack
7. **PPR changed** - Use `cacheComponents: true` instead of `experimental_ppr`

### 9. **Type-Safe Approach (Recommended)**

Use the new type helpers generated by `npx next typegen`:

```typescript
// These are globally available after typegen
import type { PageProps, LayoutProps, RouteContext } from 'next'

// Pages
export default async function Page(props: PageProps<'/blog/[slug]'>) {
  const { slug } = await props.params
}

// Layouts
export default async function Layout(props: LayoutProps<'/dashboard'>) {
  const { slug } = await props.params
}

// Route handlers
export async function GET(_req: NextRequest, ctx: RouteContext<'/api/posts/[id]'>) {
  const { id } = await ctx.params
}
```

### 10. **Migration Checklist for Your Code**

- [ ] All `await` params in pages/layouts/routes
- [ ] All `await` for cookies(), headers(), draftMode()
- [ ] All `await` for searchParams in pages
- [ ] Check fetch() calls - explicit cache options for cached data
- [ ] Run `npx next typegen` for type safety
- [ ] Check route handlers - remove sync params access
- [ ] Verify no route.ts at same level as page.ts
- [ ] Streaming responses use correct pattern with StreamingTextResponse
- [ ] Image component using remotePatterns not domains
- [ ] No use of unstable_ prefixes (cacheLife, cacheTag are stable)

**Your app is using Next.js 16.2.0 which is quite recent. The v15→v16 migration for async params is a significant breaking change if you had v14 code originally.**

