import { NextRequest, NextResponse } from "next/server";
import { v4 as uuidv4 } from "uuid";
import { parseCSV } from "@/lib/csv-parser";
import { analyzeSentiment } from "@/lib/comprehend";
import { computeAnalytics } from "@/lib/analytics";
import { setSession } from "@/lib/store";
import { Review, ReviewMetadata, ReviewSession } from "@/types";

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { type, url, csvData, platform = "Amazon" } = body;

    let reviews: Review[] = [];
    let productName = "Unknown Product";
    let productUrl = url || "";

    if (type === "url" && url) {
      // Call Lambda scraper
      const scraperUrl = process.env.SCRAPER_LAMBDA_URL;
      if (!scraperUrl) {
        return NextResponse.json(
          {
            success: false,
            error:
              "URL scraping is not configured. Please use CSV upload instead.",
          },
          { status: 400 }
        );
      }

      const scraperResponse = await fetch(scraperUrl, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ url }),
      });

      if (!scraperResponse.ok) {
        const errorData = await scraperResponse.json().catch(() => ({}));
        return NextResponse.json(
          {
            success: false,
            error:
              (errorData as { error?: string }).error ||
              "Scraping failed. Amazon may be blocking the request. Please try CSV upload instead.",
          },
          { status: 400 }
        );
      }

      const scraperData = await scraperResponse.json();
      reviews = (scraperData as { reviews: Review[]; productName: string }).reviews;
      productName = (scraperData as { productName: string }).productName || productName;
    } else if (type === "csv" && csvData) {
      reviews = parseCSV(csvData);
      // Try to extract product name from the first review or use generic
      productName = body.productName || "Uploaded Product";
    } else {
      return NextResponse.json(
        { success: false, error: "Invalid request. Provide URL or CSV data." },
        { status: 400 }
      );
    }

    if (reviews.length === 0) {
      return NextResponse.json(
        {
          success: false,
          error: "No reviews found. Please check your input and try again.",
        },
        { status: 400 }
      );
    }

    // Analyze sentiment with Comprehend
    const enrichedReviews = await analyzeSentiment(reviews);

    // Compute analytics
    const analytics = computeAnalytics(enrichedReviews);

    // Sort reviews by date (newest first)
    const dates = enrichedReviews
      .map((r) => r.date)
      .filter(Boolean)
      .sort();

    const metadata: ReviewMetadata = {
      platform,
      productName,
      productUrl,
      totalReviews: enrichedReviews.length,
      averageRating: analytics.averageRating,
      dateRange: {
        earliest: dates[0] || "Unknown",
        latest: dates[dates.length - 1] || "Unknown",
      },
      scrapedAt: new Date().toISOString(),
    };

    // Store session
    const sessionId = uuidv4();
    const session: ReviewSession = {
      sessionId,
      reviews: enrichedReviews,
      metadata,
      analytics,
    };
    setSession(sessionId, session);

    return NextResponse.json({
      success: true,
      sessionId,
      metadata,
      reviewCount: enrichedReviews.length,
    });
  } catch (error) {
    console.error("Ingest error:", error);
    return NextResponse.json(
      {
        success: false,
        error: "Failed to process reviews. Please try again.",
      },
      { status: 500 }
    );
  }
}

