          <TabsContent value="url" className="space-y-4 mt-4">
            <div>
              <label className="text-sm font-medium mb-1 block">
                Product URL
              </label>
              <Input
                placeholder="https://www.amazon.com/dp/B0..."
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                disabled={loading}
              />
              <p className="text-xs text-muted-foreground mt-1">
                Enter the Amazon product page URL. Our scraper will extract
                reviews automatically.
              </p>
            </div>
            <Button
              onClick={handleUrlSubmit}
              disabled={loading || !url.trim()}
              className="w-full"
            >
              {loading ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  Scraping Reviews...
                </>
              ) : (
                <>
                  <Globe className="w-4 h-4 mr-2" />
                  Scrape Reviews
                </>
              )}
            </Button>
          </TabsContent>

          <TabsContent value="csv" className="space-y-4 mt-4">
            <div>
              <label className="text-sm font-medium mb-1 block">
                Product Name
              </label>
              <Input
                placeholder="e.g., Apple AirPods Pro (2nd Gen)"
                value={productName}
                onChange={(e) => setProductName(e.target.value)}
                disabled={loading}
              />
            </div>

            <div>
              <label className="text-sm font-medium mb-1 block">
                Upload CSV File
              </label>
              <div
                onClick={() => fileInputRef.current?.click()}
                className="border-2 border-dashed rounded-lg p-6 text-center cursor-pointer hover:border-primary/50 transition-colors"
              >
                <input
                  ref={fileInputRef}
                  type="file"
                  accept=".csv,.txt"
                  onChange={handleFileUpload}
                  className="hidden"
                />
                {fileName ? (
                  <div className="flex items-center justify-center gap-2 text-sm">
                    <CheckCircle2 className="w-5 h-5 text-green-500" />
                    <span>{fileName}</span>
                  </div>
                ) : (
                  <div className="space-y-1">
                    <FileText className="w-8 h-8 mx-auto text-muted-foreground" />
                    <p className="text-sm text-muted-foreground">
                      Click to upload a CSV file
                    </p>
                  </div>
                )}
              </div>
            </div>

            <div>
              <label className="text-sm font-medium mb-1 block">
                Or Paste CSV Data
              </label>
              <Textarea
                placeholder={`rating,title,body,date,reviewer\n5,"Great product!","Love this item...",2024-01-15,"John D."\n3,"Okay","Average quality...",2024-01-10,"Jane S."`}
                value={csvText}
                onChange={(e) => setCsvText(e.target.value)}
                rows={6}
                disabled={loading}
                className="font-mono text-xs"
              />
              <p className="text-xs text-muted-foreground mt-1">
                Required columns: rating, body. Optional: title, date,
                reviewer, verified
              </p>
            </div>

            <Button
              onClick={handleCsvSubmit}
              disabled={loading || !csvText.trim()}
              className="w-full"
            >
              {loading ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  Processing Reviews...
                </>
              ) : (
                <>
                  <Upload className="w-4 h-4 mr-2" />
                  Upload & Analyze
                </>
              )}
            </Button>
          </TabsContent>
        </Tabs>

        {error && (
          <div className="mt-4 p-3 rounded-lg bg-destructive/10 border border-destructive/20 flex items-start gap-2">
            <AlertCircle className="w-4 h-4 text-destructive mt-0.5 shrink-0" />
            <p className="text-sm text-destructive">{error}</p>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

