"use client";

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  PieChart,
  Pie,
  Cell,
  ResponsiveContainer,
  Legend,
  Tooltip,
} from "recharts";

interface SentimentChartProps {
  breakdown: {
    positive: number;
    negative: number;
    neutral: number;
    mixed: number;
  };
}

const COLORS = {
  Positive: "#22c55e",
  Negative: "#ef4444",
  Neutral: "#94a3b8",
  Mixed: "#f59e0b",
};

export default function SentimentChart({ breakdown }: SentimentChartProps) {
  const data = [
    { name: "Positive", value: breakdown.positive },
    { name: "Negative", value: breakdown.negative },
    { name: "Neutral", value: breakdown.neutral },
    { name: "Mixed", value: breakdown.mixed },
  ].filter((d) => d.value > 0);

  return (
    <Card>
      <CardHeader>
        <CardTitle className="text-lg">Sentiment Analysis</CardTitle>
      </CardHeader>
      <CardContent>
        <ResponsiveContainer width="100%" height={250}>
          <PieChart>
            <Pie
              data={data}
              cx="50%"
              cy="50%"
              innerRadius={50}
              outerRadius={90}
              dataKey="value"
              paddingAngle={2}
              label={({ name, percent }) =>
                `${name} ${(percent * 100).toFixed(0)}%`
              }
              labelLine={false}
            >
              {data.map((entry) => (
                <Cell
                  key={entry.name}
                  fill={COLORS[entry.name as keyof typeof COLORS]}
                />
              ))}
            </Pie>
            <Tooltip
              contentStyle={{
                borderRadius: "8px",
                border: "1px solid hsl(var(--border))",
                backgroundColor: "hsl(var(--card))",
              }}
            />
            <Legend />
          </PieChart>
        </ResponsiveContainer>
        <p className="text-xs text-center text-muted-foreground mt-2">
          Powered by Amazon Comprehend
        </p>
      </CardContent>
    </Card>
  );
}

import { parse } from "csv-parse/sync";
import { Review } from "@/types";
import { v4 as uuidv4 } from "uuid";

export function parseCSV(csvContent: string): Review[] {
  const records = parse(csvContent, {
    columns: true,
    skip_empty_lines: true,
    trim: true,
    relax_column_count: true,
  });

  return records.map((record: Record<string, string>) => {
    // Support various column name formats
    const rating = parseFloat(
      record.rating || record.Rating || record.stars || record.Stars || record.score || "0"
    );
    const title =
      record.title || record.Title || record.headline || record.Headline || "";
    const body =
      record.body ||
      record.Body ||
      record.text ||
      record.Text ||
      record.review ||
      record.Review ||
      record.content ||
      record.Content ||
      "";
    const date =
      record.date || record.Date || record.timestamp || record.Timestamp || "";
    const reviewer =
      record.reviewer ||
      record.Reviewer ||
      record.author ||
      record.Author ||
      record.name ||
      record.Name ||
      "Anonymous";
    const verified =
      (record.verified || record.Verified || "").toLowerCase() === "true";

    return {
      id: uuidv4(),
      rating: Math.min(5, Math.max(0, rating)),
      title: title.trim(),
      body: body.trim(),
      date: date.trim(),
      reviewer: reviewer.trim(),
      verified,
    } satisfies Review;
  });
}

