# Create IAM role for Amplify with Bedrock and Comprehend access
aws iam create-role \
  --role-name AmplifyReviewLensRole \
  --assume-role-policy-document '{
    "Version": "2012-10-17",
    "Statement": [
      {
        "Effect": "Allow",
        "Principal": {
          "Service": "amplify.amazonaws.com"
        },
        "Action": "sts:AssumeRole"
      }
    ]
  }' \
  --tags '[{"Key": "project", "Value": "reviewlens-ai"}]' \
  2>&1

# Try without tags
aws iam create-role \
  --role-name AmplifyReviewLensRole \
  --assume-role-policy-document '{
    "Version": "2012-10-17",
    "Statement": [
      {
        "Effect": "Allow",
        "Principal": {
          "Service": "amplify.amazonaws.com"
        },
        "Action": "sts:AssumeRole"
      }
    ]
  }' \
  --query 'Role.Arn' --output text \
  2>&1

# Attach Bedrock and Comprehend policies
aws iam put-role-policy \
  --role-name AmplifyReviewLensRole \
  --policy-name BedrockComprehendAccess \
  --policy-document '{
    "Version": "2012-10-17",
    "Statement": [
      {
        "Effect": "Allow",
        "Action": [
          "bedrock:InvokeModel",
          "bedrock:InvokeModelWithResponseStream",
          "bedrock:ApplyGuardrail",
          "bedrock:GetGuardrail"
        ],
        "Resource": "*"
      },
      {
        "Effect": "Allow",
        "Action": [
          "comprehend:DetectSentiment",
          "comprehend:BatchDetectSentiment"
        ],
        "Resource": "*"
      }
    ]
  }' 2>&1

