:root {
  --background: #0a0a1a;
  --foreground: #f0f0ff;
  --card: rgba(255, 255, 255, 0.06);
  --card-foreground: #f0f0ff;
  --popover: rgba(15, 15, 35, 0.95);
  --popover-foreground: #f0f0ff;
  --primary: #8b5cf6;
  --primary-foreground: #ffffff;
  --secondary: rgba(255, 255, 255, 0.08);
  --secondary-foreground: #e0e0ff;
  --muted: rgba(255, 255, 255, 0.06);
  --muted-foreground: #9898b8;
  --accent: rgba(139, 92, 246, 0.15);
  --accent-foreground: #c4b5fd;
  --destructive: #ef4444;
  --border: rgba(255, 255, 255, 0.1);
  --input: rgba(255, 255, 255, 0.08);
  --ring: rgba(139, 92, 246, 0.5);
  --chart-1: #8b5cf6;
  --chart-2: #6366f1;
  --chart-3: #3b82f6;
  --chart-4: #06b6d4;
  --chart-5: #10b981;
  --radius: 0.75rem;
  --sidebar: rgba(15, 15, 35, 0.8);
  --sidebar-foreground: #f0f0ff;
  --sidebar-primary: #8b5cf6;
  --sidebar-primary-foreground: #ffffff;
  --sidebar-accent: rgba(139, 92, 246, 0.15);
  --sidebar-accent-foreground: #c4b5fd;
  --sidebar-border: rgba(255, 255, 255, 0.1);
  --sidebar-ring: rgba(139, 92, 246, 0.5);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
  html {
    @apply font-sans;
  }
}

/* Animated mesh gradient background */
.mesh-gradient {
  background:
    radial-gradient(ellipse at 20% 50%, rgba(99, 102, 241, 0.15) 0%, transparent 50%),
    radial-gradient(ellipse at 80% 20%, rgba(139, 92, 246, 0.12) 0%, transparent 50%),
    radial-gradient(ellipse at 50% 80%, rgba(6, 182, 212, 0.1) 0%, transparent 50%),
    #0a0a1a;
  background-size: 100% 100%;
  animation: meshShift 20s ease-in-out infinite;
}

@keyframes meshShift {
  0%, 100% {
    background-position: 0% 0%, 100% 0%, 50% 100%;
  }
  33% {
    background-position: 50% 50%, 0% 100%, 100% 0%;
  }
  66% {
    background-position: 100% 0%, 50% 50%, 0% 50%;
  }
}

/* Glassmorphism utilities */
.glass {
  background: rgba(255, 255, 255, 0.05);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.1);
}

.glass-strong {
  background: rgba(255, 255, 255, 0.08);
  backdrop-filter: blur(30px);
  -webkit-backdrop-filter: blur(30px);
  border: 1px solid rgba(255, 255, 255, 0.12);
}

.glass-card {
  background: rgba(255, 255, 255, 0.04);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid rgba(255, 255, 255, 0.08);
  transition: all 0.3s ease;
}

.glass-card:hover {
  background: rgba(255, 255, 255, 0.07);
  border-color: rgba(255, 255, 255, 0.15);
  box-shadow: 0 8px 32px rgba(139, 92, 246, 0.1);
  transform: translateY(-2px);
}

/* Gradient text */
.gradient-text {
  background: linear-gradient(135deg, #8b5cf6, #6366f1, #06b6d4);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Gradient button */
.gradient-btn {
  background: linear-gradient(135deg, #8b5cf6, #6366f1);
  position: relative;
  overflow: hidden;
  transition: all 0.3s ease;
}

.gradient-btn:hover {
  box-shadow: 0 0 30px rgba(139, 92, 246, 0.4);
  transform: translateY(-1px);
}

.gradient-btn::after {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: linear-gradient(
    45deg,
    transparent 30%,
    rgba(255, 255, 255, 0.1) 50%,
    transparent 70%
  );
  animation: shine 3s ease-in-out infinite;
}

@keyframes shine {
  0% { transform: translateX(-100%) rotate(45deg); }
  100% { transform: translateX(100%) rotate(45deg); }
}

/* Glow effects */
.glow-purple { box-shadow: 0 0 20px rgba(139, 92, 246, 0.2); }
.glow-blue { box-shadow: 0 0 20px rgba(99, 102, 241, 0.2); }
.glow-cyan { box-shadow: 0 0 20px rgba(6, 182, 212, 0.2); }
.glow-green { box-shadow: 0 0 20px rgba(16, 185, 129, 0.2); }
.glow-red { box-shadow: 0 0 20px rgba(239, 68, 68, 0.2); }

/* Animations */
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes scaleIn {
  from { opacity: 0; transform: scale(0.95); }
  to { opacity: 1; transform: scale(1); }
}

@keyframes pulse-glow {
  0%, 100% { opacity: 0.5; }
  50% { opacity: 1; }
}

.animate-fade-up {
  animation: fadeUp 0.6s ease-out forwards;
}

.animate-fade-in {
  animation: fadeIn 0.5s ease-out forwards;
}

.animate-scale-in {
  animation: scaleIn 0.4s ease-out forwards;
}

.delay-100 { animation-delay: 0.1s; }
.delay-200 { animation-delay: 0.2s; }
.delay-300 { animation-delay: 0.3s; }
.delay-400 { animation-delay: 0.4s; }

/* Dot grid pattern overlay */
.dot-grid {
  background-image: radial-gradient(rgba(255, 255, 255, 0.05) 1px, transparent 1px);
  background-size: 24px 24px;
}

/* Gradient border for inputs */
.gradient-border {
  position: relative;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: all 0.3s ease;
}

.gradient-border:focus-within {
  border-color: rgba(139, 92, 246, 0.5);
  box-shadow: 0 0 0 3px rgba(139, 92, 246, 0.1);
}

/* Scrollbar styling */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.1);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(255, 255, 255, 0.2);
}

