 12→  Shield,
 13→  ShieldAlert,
 14→  Bot,
 15→  User,
 16→  Sparkles,
 17→} from "lucide-react";
 18→import { ChatMessage, ReviewMetadata } from "@/types";
 19→import { cn } from "@/lib/utils";
 20→
 21→interface ChatInterfaceProps {
 22→  sessionId: string;
 23→  metadata: ReviewMetadata;
 24→}
 25→
 26→const SUGGESTED_QUESTIONS = [
 27→  "What are the most common complaints?",
 28→  "Summarize the positive reviews",
 29→  "What do customers say about quality?",
 30→  "Are there any recurring issues?",
 31→  "What features do reviewers mention most?",
 32→  "Compare 5-star vs 1-star review themes",
 33→];
 34→
 35→export default function ChatInterface({
 36→  sessionId,
 37→  metadata,
 38→}: ChatInterfaceProps) {
 39→  const [messages, setMessages] = useState<ChatMessage[]>([]);
 40→  const [input, setInput] = useState("");
 41→  const [isStreaming, setIsStreaming] = useState(false);
 42→  const scrollRef = useRef<HTMLDivElement>(null);
 43→  const textareaRef = useRef<HTMLTextAreaElement>(null);
 44→
 45→  useEffect(() => {
 46→    if (scrollRef.current) {
 47→      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
 48→    }
 49→  }, [messages]);
 50→
 51→  const sendMessage = async (messageText?: string) => {
 52→    const text = messageText || input.trim();
 53→    if (!text || isStreaming) return;
 54→
 55→    const userMessage: ChatMessage = {
 56→      id: crypto.randomUUID(),
 57→      role: "user",
 58→      content: text,
 59→      timestamp: new Date().toISOString(),
 60→    };
 61→
 62→    setMessages((prev) => [...prev, userMessage]);
 63→    setInput("");
 64→    setIsStreaming(true);
 65→
 66→    // Create placeholder assistant message
 67→    const assistantId = crypto.randomUUID();
 68→    const assistantMessage: ChatMessage = {
 69→      id: assistantId,
 70→      role: "assistant",
 71→      content: "",
 72→      timestamp: new Date().toISOString(),
 73→    };
 74→    setMessages((prev) => [...prev, assistantMessage]);
 75→
 76→    try {
 77→      // Build history (exclude the new user message and empty assistant)
 78→      const history = messages.map((m) => ({
 79→        role: m.role,
 80→        content: m.content,
 81→      }));
 82→
 83→      const response = await fetch("/api/chat", {
 84→        method: "POST",
 85→        headers: { "Content-Type": "application/json" },
 86→        body: JSON.stringify({ sessionId, message: text, history }),
 87→      });
 88→
 89→      if (!response.ok) {
 90→        throw new Error("Chat request failed");
 91→      }
 92→
 93→      const reader = response.body?.getReader();
 94→      if (!reader) throw new Error("No response stream");
 95→
 96→      const decoder = new TextDecoder();
 97→      let buffer = "";
 98→
 99→      while (true) {
100→        const { done, value } = await reader.read();
101→        if (done) break;
102→
103→        buffer += decoder.decode(value, { stream: true });
104→        const lines = buffer.split("\n\n");
105→        buffer = lines.pop() || "";
106→
107→        for (const line of lines) {
108→          if (!line.startsWith("data: ")) continue;
109→          const jsonStr = line.slice(6);
110→
111→          try {
112→            const data = JSON.parse(jsonStr);
113→
114→            if (data.type === "text") {
115→              setMessages((prev) =>
116→                prev.map((m) =>
117→                  m.id === assistantId
118→                    ? { ...m, content: m.content + data.content }
119→                    : m
120→                )
121→              );
122→            } else if (data.type === "guard") {
123→              setMessages((prev) =>
124→                prev.map((m) =>
125→                  m.id === assistantId
126→                    ? {
127→                        ...m,
128→                        content: data.content,
129→                        scopeGuardTriggered: true,
130→                        guardrailAction: data.action,
131→                      }
132→                    : m
133→                )
134→              );
135→            } else if (data.type === "error") {
136→              setMessages((prev) =>
137→                prev.map((m) =>
138→                  m.id === assistantId
139→                    ? { ...m, content: data.content }
140→                    : m
141→                )
142→              );
143→            }
144→          } catch {
145→            // skip invalid JSON
146→          }
147→        }
148→      }
149→    } catch {
150→      setMessages((prev) =>
151→        prev.map((m) =>
152→          m.id === assistantId
153→            ? {
154→                ...m,
155→                content:
156→                  "Sorry, something went wrong. Please try again.",
157→              }
158→            : m
159→        )
160→      );
161→    } finally {
162→      setIsStreaming(false);
163→    }
164→  };
165→
166→  const handleKeyDown = (e: React.KeyboardEvent) => {
167→    if (e.key === "Enter" && !e.shiftKey) {
168→      e.preventDefault();
169→      sendMessage();
170→    }
171→  };
172→
173→  return (
174→    <div className="flex flex-col h-[calc(100vh-10rem)]">
175→      {/* Chat header */}
176→      <div className="flex items-center gap-2 mb-4 px-1">
177→        <Shield className="w-5 h-5 text-green-500" />
178→        <div>
179→          <p className="text-sm font-medium">
180→            Guardrailed Q&A — {metadata.productName}
181→          </p>
182→          <p className="text-xs text-muted-foreground">
183→            {metadata.totalReviews} {metadata.platform} reviews loaded •
184→            Dual-layer scope guard active
185→          </p>
186→        </div>
187→      </div>
188→
189→      {/* Messages area */}
190→      <ScrollArea className="flex-1 pr-4" ref={scrollRef}>
191→        <div className="space-y-4 pb-4">
192→          {messages.length === 0 && (
193→            <div className="text-center py-12">
194→              <Bot className="w-12 h-12 mx-auto text-muted-foreground mb-4" />
195→              <h3 className="text-lg font-semibold mb-2">
196→                Ask about the reviews
197→              </h3>
198→              <p className="text-sm text-muted-foreground mb-6 max-w-md mx-auto">
199→                I can analyze the {metadata.totalReviews} ingested{" "}
200→                {metadata.platform} reviews for{" "}
201→                <strong>{metadata.productName}</strong>. I&apos;m scoped
202→                exclusively to this data.
203→              </p>
204→              <div className="flex flex-wrap gap-2 justify-center max-w-lg mx-auto">
205→                {SUGGESTED_QUESTIONS.map((q) => (
206→                  <button
207→                    key={q}
208→                    onClick={() => sendMessage(q)}
209→                    className="text-xs px-3 py-1.5 rounded-full border hover:bg-muted transition-colors text-left"
210→                  >
211→                    <Sparkles className="w-3 h-3 inline mr-1 text-primary" />
212→                    {q}
213→                  </button>
214→                ))}
215→              </div>
216→            </div>
217→          )}
218→
219→          {messages.map((msg) => (
220→            <div
221→              key={msg.id}
