33→              className={`${getSize(kw.count)} cursor-default`}
34→            >
35→              {kw.word}
36→              <span className="ml-1 opacity-60">{kw.count}</span>
37→            </Badge>
38→          ))}
39→        </div>
40→      </CardContent>
41→    </Card>
